const panelMap = { grid: GridPanel, ui: UIPanel, editorial: EditorialPanel, dots: DotsPanel, code: CodePanel, pink: PinkPanel, wave: WavePanel, chart: ChartPanel, dark: DarkPanel };
function VideoPanel({ src }) {
  return (
    <div style={{ width: '100%', height: '100%', overflow: 'hidden' }}>
      <video
        src={src}
        autoPlay
        loop
        muted
        playsInline
        style={{ width: '100%', height: '100%', objectFit: 'cover' }}
      />
    </div>
  );
}

function ImagePanel({ src }) {
  return (
    <div style={{ width: '100%', height: '100%', overflow: 'hidden' }}>
      <img src={src} alt='' style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
    </div>
  );
}

function TrophyIcon() {
  const [hovered, setHovered] = useState(false);
  return (
    <div style={{ position: "relative", flexShrink: 0, marginLeft: -14 }}
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
    >
      <img
        src="/trophy.png"
        alt="Award trophy"
        style={{
          width: 90,
          height: 90,
          objectFit: "contain",
          mixBlendMode: "multiply",
          transform: hovered ? "rotate(5deg)" : "rotate(0deg)",
          transition: "transform 0.35s cubic-bezier(0.34, 1.56, 0.64, 1)",
          cursor: "pointer",
          display: "block",
        }}
      />
      {hovered && (
        <div style={{
          position: "absolute",
          bottom: "calc(100% + 8px)",
          left: "50%",
          transform: "translateX(-50%)",
          background: "#fff",
          color: "#333",
          fontFamily: "'DM Sans', sans-serif",
          fontSize: 12,
          fontWeight: 400,
          lineHeight: 1.4,
          padding: "8px 12px",
          borderRadius: 6,
          whiteSpace: "nowrap",
          boxShadow: "0 2px 16px rgba(0,0,0,0.10)",
          border: "1px solid #e8e8e8",
          pointerEvents: "none",
          zIndex: 10,
        }}>
          Rising Star in Sports Betting Innovation (Supplier)
          <div style={{
            position: "absolute",
            top: "100%",
            left: "50%",
            transform: "translateX(-50%)",
            width: 0,
            height: 0,
            borderLeft: "6px solid transparent",
            borderRight: "6px solid transparent",
            borderTop: "6px solid #e8e8e8",
          }} />
        </div>
      )}
    </div>
  );
}

export default function ProjectSection() {

  return (
    <section style={{ background: "#fff" }}>
    <div className="max-w-5xl mx-auto px-6" style={{ paddingTop: 60, paddingBottom: 60 }}>
      <div className="flex items-start justify-between mb-12">
        <div>
          <div className="flex items-center gap-2 mb-1">
            <FolderOpen size={20} strokeWidth={1.8} className="text-[#1C1C1C]" />
            <h2 className="text-2xl font-bold text-[#1C1C1C] tracking-tight" style={{ fontFamily: "Arial, Helvetica, sans-serif" }}>
              Featured Projects
            </h2>
          </div>
          <p className="text-sm text-[#888888] ml-7" style={{ fontFamily: "Arial, Helvetica, sans-serif" }}>
            A selection of product work
          </p>
        </div>
        <Link href="/projects" style={{ fontFamily: "Arial, Helvetica, sans-serif", fontSize: 13, fontWeight: 500, color: "#888", textDecoration: "none" }}>
          See All →
        </Link>
      </div>

      <div style={{ display: "flex", flexDirection: "column", gap: 0 }}>
        {projects.map((project) => {
          const resolvedPanels = project.panels.map(p =>
            typeof p === "string"
              ? { Component: panelMap[p], src: null }
              : p.type === "video"
              ? { Component: VideoPanel, src: p.src }
              : { Component: ImagePanel, src: p.src }
          );

          const cardContent = (
            <>
              {/* Triptych */}
              <div style={{ display: "grid", gridTemplateColumns: resolvedPanels.map(() => "1fr").join(" "), gap: 10, height: 193, overflow: "hidden" }}>
                {resolvedPanels.map(({ Component, src }, i) => {
                  return (
                    <div
                      key={i}
                      style={{
                        overflow: "hidden",
                        borderRadius: 24,
                      }}
                    >
                      <Component src={src} />
                    </div>
                  );
                })}
              </div>

              {/* Info row — mirrors triptych columns so description aligns with 2nd image */}
              <div style={{ display: "grid", gridTemplateColumns: resolvedPanels.map(() => "1fr").join(" "), gap: 10, padding: "20px 0 4px" }}>
                <div style={{ display: "flex", alignItems: "center", gap: 4 }}>
                  <div>
                    <h2 style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 20, fontWeight: 700, margin: "0 0 5px", color: "#111", letterSpacing: "-0.2px" }}>
                      {project.title}
                    </h2>
                    <p style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 12, color: "#999", margin: 0 }}>
                      {project.date}
                    </p>
                  </div>
                  {project.id === 1 && <TrophyIcon />}
                </div>
                <div style={{ gridColumn: "2 / -1" }}>
                  <p style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 14, lineHeight: 1.7, color: "#333", margin: "0 0 16px" }}>
                    {project.description}
                  </p>
                </div>
              </div>
            </>
          );

          return project.link ? (
            <Link
              key={project.id}
              href={project.link}

              style={{
                display: "block",
                textDecoration: "none",
                cursor: "pointer",
              }}
            >
              {cardContent}
            </Link>
          ) : (
            <div key={project.id} style={{ borderTop: "1px solid #e8e8e8", paddingTop: 40, paddingBottom: 40 }}>
              {cardContent}
            </div>
          );
        })}
        <div style={{ borderTop: "1px solid #e8e8e8" }} />
      </div>
    </div>
    </section>
  );
}
